{
  "enrichedGoal": "TypeScript + React + Vite TODO app with SQLite persistence",
  "assumptions": ["single-user", "desktop-only"],
  "questions": [],
  "prd": {
    "overview": "A minimal local TODO app for single-user productivity.",
    "goals": ["create / edit / delete a task in <100ms", "persist across restart without data loss"],
    "userStories": [
      {
        "id": "US-001",
        "title": "Create a task",
        "description": "As a user, I want to type a task and press Enter so that it appears immediately.",
        "acceptanceCriteria": ["empty input rejected", "persists to SQLite before UI clears"]
      }
    ],
    "nonGoals": ["no multi-device sync", "no shared lists"],
    "successMetrics": ["all unit tests pass", "survives kill+restart"]
  },
  "mvp": {
    "pitch": "A keyboard-first single-user TODO that just works offline.",
    "features": ["create / delete", "toggle done"],
    "deferred": ["auth", "tagging"],
    "scope": "~3 days"
  },
  "ready": false
}
